SELECT species_count
   FROM biodiversity_metrics
   WHERE species_count < (SELECT AVG(species_count) FROM biodiversity_metrics);

SELECT metric_id, site_id, species_count
FROM biodiversity_metrics
WHERE diversity_type = 2;

SELECT site_name, location, latitude, longitude
FROM sites
ORDER BY latitude DESC;

SELECT COUNT(DISTINCT species_id) AS number_of_species
FROM species_metrics
WHERE species_id IS NOT NULL;

SELECT site_id, AVG(observed_value) as avg_observed_value
FROM biodiversity_metrics
GROUP BY site_id;

SELECT researcher_name, affiliation, research_interests
FROM researchers
WHERE researcher_id = 0;

SELECT AVG(estimator_value) AS average_estimated_value
FROM biodiversity_metrics
WHERE site_id = 10 AND diversity_type = 2;
